import{_ as s,o as e,c as n,ag as t}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"Algorithms (Theory)","description":"","frontmatter":{"title":"Algorithms (Theory)","parent":"Solution Development (Theory)","grand_parent":"Theory (Paper 2)","nav_order":2},"headers":[],"relativePath":"theory/programming/algorithms-theory.md","filePath":"theory/programming/algorithms-theory.md"}'),r={name:"theory/programming/algorithms-theory.md"};function i(o,a,l,p,d,c){return e(),n("div",null,[...a[0]||(a[0]=[t(`<h1 id="algorithms-—-theory" tabindex="-1">Algorithms — Theory <a class="header-anchor" href="#algorithms-—-theory" aria-label="Permalink to &quot;Algorithms — Theory&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>Algorithms are covered in <strong>8 hours</strong> of the Grade 10 theory section. Expect exam questions on drawing flowcharts, tracing algorithms, writing pseudocode, and identifying algorithm types.</p></div><hr><h2 id="_1-what-is-an-algorithm" tabindex="-1">1. What Is an Algorithm? <a class="header-anchor" href="#_1-what-is-an-algorithm" aria-label="Permalink to &quot;1. What Is an Algorithm?&quot;">​</a></h2><p>An <strong>algorithm</strong> is a step-by-step procedure used to solve a problem. Computer programs are simply lists of instructions — which means every program you write is, at its core, an algorithm. If an algorithm is not correct, it will cause errors in the resulting program.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>Always define an algorithm as: <em>a finite, ordered set of unambiguous steps that solves a problem and produces at least one result.</em></p></div><h3 id="everyday-example-—-making-hot-chocolate" tabindex="-1">Everyday Example — Making Hot Chocolate <a class="header-anchor" href="#everyday-example-—-making-hot-chocolate" aria-label="Permalink to &quot;Everyday Example — Making Hot Chocolate&quot;">​</a></h3><p>Consider the steps to make a cup of hot chocolate:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Boil water in the kettle.</span></span>
<span class="line"><span>2. Place a mug on the counter.</span></span>
<span class="line"><span>3. Add two teaspoons of hot chocolate powder to the mug.</span></span>
<span class="line"><span>4. Pour the boiling water into the mug.</span></span>
<span class="line"><span>5. Stir until the powder is dissolved.</span></span>
<span class="line"><span>6. Add milk or sugar if desired.</span></span>
<span class="line"><span>7. Serve.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>This is an algorithm — it is a finite, ordered list of clear steps that ends with a result (a cup of hot chocolate). Each step is simple, specific, and cannot be misunderstood.</p><hr><h2 id="_2-properties-of-a-good-algorithm" tabindex="-1">2. Properties of a Good Algorithm <a class="header-anchor" href="#_2-properties-of-a-good-algorithm" aria-label="Permalink to &quot;2. Properties of a Good Algorithm&quot;">​</a></h2><p>For an algorithm to be considered correct and usable, it must meet all of the following criteria:</p><table tabindex="0"><thead><tr><th>#</th><th>Criterion</th><th>Explanation</th></tr></thead><tbody><tr><td>1</td><td><strong>Finite number of steps</strong></td><td>The algorithm must eventually end — it cannot run forever.</td></tr><tr><td>2</td><td><strong>Easy to understand</strong></td><td>Steps must be written so any person (or computer) can follow them without guessing.</td></tr><tr><td>3</td><td><strong>Detailed and specific</strong></td><td>Vague instructions like &quot;make it work&quot; are not acceptable.</td></tr><tr><td>4</td><td><strong>Clear and unambiguous</strong></td><td>Each step must have only one possible interpretation.</td></tr><tr><td>5</td><td><strong>Single task per step</strong></td><td>Each step should do exactly one thing — not bundle several actions together.</td></tr><tr><td>6</td><td><strong>Most basic level</strong></td><td>Steps should not require prior expert knowledge to interpret.</td></tr><tr><td>7</td><td><strong>Repetitions have clear endings</strong></td><td>Any loop must have a condition that will eventually stop it.</td></tr><tr><td>8</td><td><strong>At least one result</strong></td><td>Every algorithm must produce some output or result.</td></tr></tbody></table><hr><h2 id="_3-precision-vs-order-—-evaluating-algorithm-quality" tabindex="-1">3. Precision vs Order — Evaluating Algorithm Quality <a class="header-anchor" href="#_3-precision-vs-order-—-evaluating-algorithm-quality" aria-label="Permalink to &quot;3. Precision vs Order — Evaluating Algorithm Quality&quot;">​</a></h2><p>Two key criteria are used to evaluate how well an algorithm works:</p><h3 id="precision" tabindex="-1">Precision <a class="header-anchor" href="#precision" aria-label="Permalink to &quot;Precision&quot;">​</a></h3><p><strong>Precision</strong> measures how accurately and reliably an algorithm solves a problem. A precise algorithm always produces the correct result for all valid inputs.</p><h3 id="order" tabindex="-1">Order <a class="header-anchor" href="#order" aria-label="Permalink to &quot;Order&quot;">​</a></h3><p><strong>Order</strong> measures the total number of steps needed — including repeated steps — to complete the algorithm. A lower order (fewer steps) is generally more efficient.</p><h3 id="example-baking-a-cake" tabindex="-1">Example: Baking a Cake <a class="header-anchor" href="#example-baking-a-cake" aria-label="Permalink to &quot;Example: Baking a Cake&quot;">​</a></h3><p><strong>Imprecise algorithm:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Mix some ingredients together.</span></span>
<span class="line"><span>2. Bake for a while.</span></span>
<span class="line"><span>3. Take the cake out when it looks done.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>This algorithm is <strong>imprecise</strong> — &quot;some ingredients&quot;, &quot;a while&quot;, and &quot;looks done&quot; are vague and will produce different (possibly wrong) results every time.</p><p><strong>Precise algorithm:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. Preheat the oven to 180°C.</span></span>
<span class="line"><span>2. Measure 200 g of flour and sift into a bowl.</span></span>
<span class="line"><span>3. Add 100 g of sugar, 2 eggs, 100 ml of milk, and 5 ml of baking powder.</span></span>
<span class="line"><span>4. Mix on medium speed for 3 minutes.</span></span>
<span class="line"><span>5. Pour batter into a greased 20 cm round tin.</span></span>
<span class="line"><span>6. Bake at 180°C for 35 minutes.</span></span>
<span class="line"><span>7. Insert a skewer into the centre — if it comes out clean, the cake is done.</span></span>
<span class="line"><span>8. Remove from the oven and allow to cool for 10 minutes before serving.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>Every measurement, time, and condition is exact — this algorithm will produce the same correct result every time.</p><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>In an exam, you may be asked to identify what makes an algorithm imprecise. Look for vague words: <em>&quot;some&quot;</em>, <em>&quot;a bit&quot;</em>, <em>&quot;a while&quot;</em>, <em>&quot;a few&quot;</em>, <em>&quot;when ready&quot;</em>, <em>&quot;looks right&quot;</em>, etc. Each vague word loses a mark.</p></div><hr><h2 id="_4-how-to-write-an-algorithm" tabindex="-1">4. How to Write an Algorithm <a class="header-anchor" href="#_4-how-to-write-an-algorithm" aria-label="Permalink to &quot;4. How to Write an Algorithm&quot;">​</a></h2><p>When writing an algorithm in the SA IT exam, follow these conventions:</p><ul><li>Number every step starting from 1.</li><li>Write in plain everyday language (not code — unless pseudocode is specifically asked for).</li><li>Use the word <strong>READ</strong> or <strong>INPUT</strong> to accept data from the user.</li><li>Use the word <strong>DISPLAY</strong>, <strong>PRINT</strong>, or <strong>OUTPUT</strong> to show a result.</li><li>Keep each step to a single action.</li><li>Include a <strong>START</strong> and an <strong>END</strong>.</li></ul><h3 id="example-convert-temperature-from-celsius-to-fahrenheit" tabindex="-1">Example: Convert Temperature from Celsius to Fahrenheit <a class="header-anchor" href="#example-convert-temperature-from-celsius-to-fahrenheit" aria-label="Permalink to &quot;Example: Convert Temperature from Celsius to Fahrenheit&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. START</span></span>
<span class="line"><span>2. READ celsius</span></span>
<span class="line"><span>3. CALCULATE fahrenheit = (celsius × 9 / 5) + 32</span></span>
<span class="line"><span>4. DISPLAY fahrenheit</span></span>
<span class="line"><span>5. END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><hr><h2 id="_5-flowcharts" tabindex="-1">5. Flowcharts <a class="header-anchor" href="#_5-flowcharts" aria-label="Permalink to &quot;5. Flowcharts&quot;">​</a></h2><p>A <strong>flowchart</strong> is a visual (diagram) representation of an algorithm. Each step is drawn as a specific shape, and arrows show the direction of flow between steps.</p><h3 id="flowchart-symbols" tabindex="-1">Flowchart Symbols <a class="header-anchor" href="#flowchart-symbols" aria-label="Permalink to &quot;Flowchart Symbols&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Symbol</th><th>Shape</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Oval / Terminator</strong></td><td>Rounded ends</td><td>Start or End of the algorithm</td></tr><tr><td><strong>Rectangle / Process</strong></td><td>Plain rectangle</td><td>A processing step — calculation or assignment</td></tr><tr><td><strong>Diamond / Decision</strong></td><td>Diamond (rhombus)</td><td>A YES/NO question — creates a branch</td></tr><tr><td><strong>Parallelogram</strong></td><td>Slanted rectangle</td><td>Input or Output</td></tr><tr><td><strong>Arrow</strong></td><td>Line with arrowhead</td><td>Direction of flow — connects shapes</td></tr></tbody></table><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>You must be able to draw these shapes and label them correctly. In an exam, marks are awarded for the correct shape, the correct label inside the shape, and the correct arrows between shapes.</p></div><h3 id="flowchart-example-is-a-number-even-or-odd" tabindex="-1">Flowchart Example: Is a Number Even or Odd? <a class="header-anchor" href="#flowchart-example-is-a-number-even-or-odd" aria-label="Permalink to &quot;Flowchart Example: Is a Number Even or Odd?&quot;">​</a></h3><p>The following describes a flowchart read from top to bottom:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[OVAL]              START</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>[PARALLELOGRAM]     INPUT number</span></span>
<span class="line"><span>       ↓</span></span>
<span class="line"><span>[DIAMOND]           Is number MOD 2 = 0?</span></span>
<span class="line"><span>    YES ↓                       ↓ NO</span></span>
<span class="line"><span>[PARALLELOGRAM]         [PARALLELOGRAM]</span></span>
<span class="line"><span>DISPLAY &quot;Even&quot;          DISPLAY &quot;Odd&quot;</span></span>
<span class="line"><span>    ↓                           ↓</span></span>
<span class="line"><span>    └──────────┬────────────────┘</span></span>
<span class="line"><span>               ↓</span></span>
<span class="line"><span>[OVAL]              END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>In this flowchart:</p><ul><li>The <strong>diamond</strong> tests whether <code>number MOD 2 = 0</code> (i.e. whether the remainder when dividing by 2 is zero — meaning the number is even).</li><li>The <strong>YES</strong> branch (left) displays &quot;Even&quot;.</li><li>The <strong>NO</strong> branch (right) displays &quot;Odd&quot;.</li><li>Both branches rejoin and lead to the <strong>END</strong> oval.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>The <strong>MOD</strong> operator gives the remainder after division. <code>7 MOD 2 = 1</code> (odd), <code>8 MOD 2 = 0</code> (even). This is one of the most common flowchart and pseudocode examples in CAPS papers.</p></div><hr><h2 id="_6-pseudocode-conventions-sa-it-exams" tabindex="-1">6. Pseudocode Conventions (SA IT Exams) <a class="header-anchor" href="#_6-pseudocode-conventions-sa-it-exams" aria-label="Permalink to &quot;6. Pseudocode Conventions (SA IT Exams)&quot;">​</a></h2><p><strong>Pseudocode</strong> is a structured, human-readable way of writing algorithm steps. It is closer to actual code, but not tied to any programming language. The SA CAPS IT exam uses specific keywords — you must use these exact forms.</p><h3 id="input-and-output" tabindex="-1">Input and Output <a class="header-anchor" href="#input-and-output" aria-label="Permalink to &quot;Input and Output&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Keyword</th><th>Meaning</th><th>Example</th></tr></thead><tbody><tr><td><code>READ</code> or <code>INPUT</code></td><td>Accept a value from the user</td><td><code>READ iAge</code></td></tr><tr><td><code>DISPLAY</code>, <code>PRINT</code>, or <code>OUTPUT</code></td><td>Show a value to the user</td><td><code>DISPLAY &quot;Hello&quot;</code></td></tr></tbody></table><h3 id="selection-decision-—-if" tabindex="-1">Selection (Decision) — IF <a class="header-anchor" href="#selection-decision-—-if" aria-label="Permalink to &quot;Selection (Decision) — IF&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IF condition THEN</span></span>
<span class="line"><span>    [steps if true]</span></span>
<span class="line"><span>ELSE</span></span>
<span class="line"><span>    [steps if false]</span></span>
<span class="line"><span>ENDIF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IF iMark &gt;= 50 THEN</span></span>
<span class="line"><span>    DISPLAY &quot;PASSED&quot;</span></span>
<span class="line"><span>ELSE</span></span>
<span class="line"><span>    DISPLAY &quot;FAILED&quot;</span></span>
<span class="line"><span>ENDIF</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="counted-loop-—-for" tabindex="-1">Counted Loop — FOR <a class="header-anchor" href="#counted-loop-—-for" aria-label="Permalink to &quot;Counted Loop — FOR&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FOR counter := start TO end DO</span></span>
<span class="line"><span>    [repeated steps]</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><strong>Example — display numbers 1 to 5:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FOR iCount := 1 TO 5 DO</span></span>
<span class="line"><span>    DISPLAY iCount</span></span>
<span class="line"><span>ENDFOR</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="condition-controlled-loop-—-while" tabindex="-1">Condition-controlled Loop — WHILE <a class="header-anchor" href="#condition-controlled-loop-—-while" aria-label="Permalink to &quot;Condition-controlled Loop — WHILE&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WHILE condition DO</span></span>
<span class="line"><span>    [repeated steps]</span></span>
<span class="line"><span>ENDWHILE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>The condition is tested <strong>before</strong> each iteration. If the condition is false from the start, the loop body never runs.</p><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WHILE iCount &lt;= 10 DO</span></span>
<span class="line"><span>    DISPLAY iCount</span></span>
<span class="line"><span>    iCount := iCount + 1</span></span>
<span class="line"><span>ENDWHILE</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="post-test-loop-—-repeat-until" tabindex="-1">Post-test Loop — REPEAT...UNTIL <a class="header-anchor" href="#post-test-loop-—-repeat-until" aria-label="Permalink to &quot;Post-test Loop — REPEAT...UNTIL&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>REPEAT</span></span>
<span class="line"><span>    [repeated steps]</span></span>
<span class="line"><span>UNTIL condition</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>The condition is tested <strong>after</strong> each iteration. The loop body always runs <strong>at least once</strong>.</p><p><strong>Example:</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>REPEAT</span></span>
<span class="line"><span>    READ iNumber</span></span>
<span class="line"><span>UNTIL iNumber &gt; 0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>Know the difference: <strong>WHILE</strong> tests the condition first (may never run); <strong>REPEAT...UNTIL</strong> tests the condition last (always runs at least once). Exam questions often ask you to choose the correct loop type for a given scenario.</p></div><hr><h2 id="_7-types-of-algorithms-caps-prescribed" tabindex="-1">7. Types of Algorithms (CAPS-Prescribed) <a class="header-anchor" href="#_7-types-of-algorithms-caps-prescribed" aria-label="Permalink to &quot;7. Types of Algorithms (CAPS-Prescribed)&quot;">​</a></h2><h3 id="sequential-algorithm" tabindex="-1">Sequential Algorithm <a class="header-anchor" href="#sequential-algorithm" aria-label="Permalink to &quot;Sequential Algorithm&quot;">​</a></h3><p>Steps are executed <strong>one after another, in a fixed order</strong>. No decisions, no loops.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. START</span></span>
<span class="line"><span>2. READ firstName</span></span>
<span class="line"><span>3. READ lastName</span></span>
<span class="line"><span>4. DISPLAY firstName + &quot; &quot; + lastName</span></span>
<span class="line"><span>5. END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="decision-algorithm" tabindex="-1">Decision Algorithm <a class="header-anchor" href="#decision-algorithm" aria-label="Permalink to &quot;Decision Algorithm&quot;">​</a></h3><p>Contains <strong>at least one branching point</strong> — a condition that determines which path to follow. Uses IF...THEN...ELSE or CASE structures.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. START</span></span>
<span class="line"><span>2. READ iTemperature</span></span>
<span class="line"><span>3. IF iTemperature &gt; 30 THEN</span></span>
<span class="line"><span>4.     DISPLAY &quot;Hot day&quot;</span></span>
<span class="line"><span>5. ELSE</span></span>
<span class="line"><span>6.     DISPLAY &quot;Cool day&quot;</span></span>
<span class="line"><span>7. ENDIF</span></span>
<span class="line"><span>8. END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="repetition-algorithm" tabindex="-1">Repetition Algorithm <a class="header-anchor" href="#repetition-algorithm" aria-label="Permalink to &quot;Repetition Algorithm&quot;">​</a></h3><p>Contains <strong>at least one loop</strong> — a set of steps that repeats. Uses FOR, WHILE, or REPEAT...UNTIL.</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. START</span></span>
<span class="line"><span>2. iTotal := 0</span></span>
<span class="line"><span>3. FOR iCount := 1 TO 5 DO</span></span>
<span class="line"><span>4.     READ iNumber</span></span>
<span class="line"><span>5.     iTotal := iTotal + iNumber</span></span>
<span class="line"><span>6. ENDFOR</span></span>
<span class="line"><span>7. DISPLAY iTotal</span></span>
<span class="line"><span>8. END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10 — Foundation</p><p>An algorithm can belong to more than one type. A loop that contains an IF statement is both a <strong>repetition</strong> and a <strong>decision</strong> algorithm. When asked to identify the type, name all that apply.</p></div><hr><h2 id="_8-tracing-an-algorithm" tabindex="-1">8. Tracing an Algorithm <a class="header-anchor" href="#_8-tracing-an-algorithm" aria-label="Permalink to &quot;8. Tracing an Algorithm&quot;">​</a></h2><p><strong>Tracing</strong> means manually working through an algorithm step by step, tracking the value of each variable at each point. A <strong>trace table</strong> is used to record these values.</p><h3 id="example-trace-the-following-with-input-7" tabindex="-1">Example: Trace the following with input <code>7</code> <a class="header-anchor" href="#example-trace-the-following-with-input-7" aria-label="Permalink to &quot;Example: Trace the following with input \`7\`&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. START</span></span>
<span class="line"><span>2. READ iNumber</span></span>
<span class="line"><span>3. IF iNumber MOD 2 = 0 THEN</span></span>
<span class="line"><span>4.     DISPLAY &quot;Even&quot;</span></span>
<span class="line"><span>5. ELSE</span></span>
<span class="line"><span>6.     DISPLAY &quot;Odd&quot;</span></span>
<span class="line"><span>7. ENDIF</span></span>
<span class="line"><span>8. END</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><table tabindex="0"><thead><tr><th>Step</th><th>Action</th><th><code>iNumber</code></th><th>Output</th></tr></thead><tbody><tr><td>2</td><td>READ iNumber</td><td>7</td><td>—</td></tr><tr><td>3</td><td>7 MOD 2 = 1 → not 0 → condition is <strong>FALSE</strong></td><td>7</td><td>—</td></tr><tr><td>6</td><td>DISPLAY &quot;Odd&quot;</td><td>7</td><td>Odd</td></tr><tr><td>8</td><td>END</td><td>—</td><td>—</td></tr></tbody></table><div class="tip custom-block github-alert"><p class="custom-block-title">Exam Tip</p><p>In a trace table, set up one column per variable, plus an Output column. Fill in values row by row. Only write a new value in a variable&#39;s column when that variable actually changes.</p></div><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>Key Point</th></tr></thead><tbody><tr><td>Algorithm</td><td>Finite, ordered, unambiguous steps that solve a problem</td></tr><tr><td>Precision</td><td>How accurately the algorithm produces the correct result</td></tr><tr><td>Order</td><td>Total number of steps — measures efficiency</td></tr><tr><td>Flowchart</td><td>Visual representation using standard shapes</td></tr><tr><td>Pseudocode</td><td>Human-readable code-like notation using CAPS keywords</td></tr><tr><td>Sequential</td><td>Steps in order only — no branches, no loops</td></tr><tr><td>Decision</td><td>Contains at least one IF/CASE branch</td></tr><tr><td>Repetition</td><td>Contains at least one loop (FOR, WHILE, REPEAT)</td></tr></tbody></table>`,93)])])}const m=s(r,[["render",i]]);export{u as __pageData,m as default};
